sql:
SELECT province_state, confirmed
FROM epidemiological_data
WHERE confirmed > (SELECT AVG(confirmed) FROM epidemiological_data);

SELECT observation_id, confirmed, deaths, recovered
FROM epidemiological_data
WHERE deaths > 100 AND vaccinations > 1000000;

external_knowledge:
- 'wayward ships' metaphorically refers to the observations;
- 'charted through the waters' represents the locations (province or state, country or region) where the observations were made;
- 'tumultuous year of 2020' refers to the time period between 2020-01-01 and 2020-12-31;
- 'flag of health' refers to the user role being 'health official';
- 'carrying the burden of confirmed cases' refers to observations where the number of confirmed cases is greater than 0.

sql:
SELECT e.observation_date, e.confirmed
FROM epidemiological_data e
WHERE e.observation_date > DATE('now', '-7 days') AND e.reproduction_number > 1.0;

external_knowledge:
- "shadow dates" refers to the dates of observation;
- "tales of the sick, dead, and risen" denote the number of confirmed cases, deaths, and recovered cases, respectively;
- "lands of the trustworthy" refers to countries or regions where the data source's reliability is not 'low';
- "whispers of infection carry more weight than a handful of sand" implies that the positivity rate of tests is more than 5%.

sql:
SELECT DISTINCT country_region
FROM locations
ORDER BY country_region ASC;

SELECT AVG(positivity_rate) AS average_positivity_rate
FROM epidemiological_data
WHERE confirmed > 10;
